+    #[test]
+    fn display_http_error() {
+        // Create an HTTP error via reqwest builder failure
+        let err = reqwest::Client::builder()
+            .build()
+            .unwrap()
+            .get("://invalid")
+            .build();
+        if let Err(e) = err {
+            let ae = AirtableError::Http(e);
+            let display = ae.to_string();
+            assert!(display.starts_with("HTTP error:"), "got: {display}");
+        }
